1	export type Customer = {
2	  yearsWithMHPCO: number;
3	  priorContracts: number;
4	};
5	
6	export type Item = Record<string, unknown>;
7	
8	export type Policy = {
9	  customer: Customer;
10	  items: Item[];
11	};
12	
13	export type QuoteResult = {
14	  premium: number;
15	};
16	
17	export type ClaimResult = {
18	  payout: number;
19	  remainingCap: number;
20	};
21	
22	const PROCESSING_FEE = 5;
23	const COMPONENT_BASE_PREMIUM = 25;
24	const COMPONENT_BLOCK_SIZE = 3;
25	const COMPONENT_BLOCK_PREMIUM = 60;
26	
27	const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
28	  sword: 100,
29	  amulet: 60,
30	  staff: 80,
31	  potion: 40,
32	  component: COMPONENT_BASE_PREMIUM,
33	};
34	
35	const basePremiumForItem = (item: Item): number =>
36	  BASE_PREMIUM_BY_ITEM_TYPE[item.type as string] ?? 0;
37	
38	const isComponent = (item: Item): boolean => item.type === "component";
39	
40	const groupComponentsByType = (items: Item[]): Map<string, number> => {
41	  const groups = new Map<string, number>();
42	  for (const item of items.filter(isComponent)) {
43	    const key = item.componentType as string;
44	    groups.set(key, (groups.get(key) ?? 0) + 1);
45	  }
46	  return groups;
47	};
48	
49	const componentGroupPremium = (count: number): number =>
50	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PREMIUM : count * COMPONENT_BASE_PREMIUM;
51	
52	const componentsPremium = (items: Item[]): number => {
53	  const groups = groupComponentsByType(items);
54	  let total = 0;
55	  for (const count of groups.values()) {
56	    total += componentGroupPremium(count);
57	  }
58	  return total;
59	};
60	
61	const CURSE_SURCHARGE_RATE = 0.5;
62	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
63	const HIGH_ENCHANTMENT_THRESHOLD = 5;
64	
65	type ItemModifier = (item: Item, base: number) => number;
66	
67	const curseModifier: ItemModifier = (item, base) =>
68	  item.cursed === true ? base * CURSE_SURCHARGE_RATE : 0;
69	
70	const highEnchantmentModifier: ItemModifier = (item, base) =>
71	  (item.enchantment as number) >= HIGH_ENCHANTMENT_THRESHOLD
72	    ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
73	    : 0;
74	
75	const ITEM_MODIFIERS: ItemModifier[] = [curseModifier, highEnchantmentModifier];
76	
77	const itemPremium = (item: Item): number => {
78	  const base = basePremiumForItem(item);
79	  return ITEM_MODIFIERS.reduce(
80	    (premium, modifier) => premium + modifier(item, base),
81	    base,
82	  );
83	};
84	
85	const nonComponentsPremium = (items: Item[]): number =>
86	  items
87	    .filter((item) => !isComponent(item))
88	    .reduce((sum, item) => sum + itemPremium(item), 0);
89	
90	export function quote(policy: Policy): QuoteResult {
91	  const itemsTotal = nonComponentsPremium(policy.items) + componentsPremium(policy.items);
92	  return { premium: itemsTotal + PROCESSING_FEE };
93	}
94	
95	export function claim(..._args: unknown[]): ClaimResult {
96	  return undefined as unknown as ClaimResult;
97	}
